#!/usr/bin/env perl
use strict;
use warnings;
use DBI;
use Config::Tiny;
use File::Spec;
use Carp qw(croak);

sub get_db_config {
    my $config_file = $ENV{DB_CONFIG_FILE} || '/etc/legacy_app/database.conf';
    
    unless (-f $config_file && -r $config_file) {
        croak "Configuration file not found or not readable: $config_file";
    }
    
    my $config = Config::Tiny->read($config_file)
        or croak "Failed to read config file: " . Config::Tiny->errstr;
    
    return $config->{database};
}

sub connect_to_database {
    my $config = get_db_config();
    
    my $database = $config->{database} || croak "Database name not configured";
    my $host     = $config->{host}     || 'localhost';
    my $port     = $config->{port}     || 3306;
    my $username = $config->{username} || croak "Database username not configured";
    my $password = $config->{password} || croak "Database password not configured";
    
    my $dsn = "DBI:mysql:database=$database;host=$host;port=$port";
    
    my $dbh = DBI->connect(
        $dsn,
        $username,
        $password,
        {
            RaiseError       => 1,
            AutoCommit       => 1,
            PrintError       => 0,
            mysql_enable_utf8 => 1,
        }
    ) or croak "Database connection failed: " . DBI->errstr;
    
    return $dbh;
}

my $dbh = connect_to_database();

print "Database connection established successfully\n";

$dbh->disconnect();